+
+using namespace llvm;
+using namespace PatternMatch;
+
+// This file in LLVM contains many helper routines above this point.
+// They are unchanged by this patch and omitted here for brevity in the review
+// context. The functional change is the new fold in visitSelectInst below.
+
+Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
+  Value *CondVal = SI.getCondition();
+  Value *TrueVal = SI.getTrueValue();
+  Value *FalseVal = SI.getFalseValue();
+  Type *SelType = SI.getType();
+
+  // Fold:
+  // select(C2, select(C1, A, B), select(C1, B, A))
+  //   --> select(xor(C1, C2), B, A)
+  //
+  // The result is A iff C1 == C2, otherwise B.
+  if (CondVal->getType()->isIntegerTy(1)) {
+    auto *TrueSI = dyn_cast<SelectInst>(TrueVal);
+    auto *FalseSI = dyn_cast<SelectInst>(FalseVal);
+    if (TrueSI && FalseSI &&
+        TrueSI->getCondition() == FalseSI->getCondition() &&
+        TrueSI->getCondition()->getType()->isIntegerTy(1) &&
+        TrueSI->getTrueValue() == FalseSI->getFalseValue() &&
+        TrueSI->getFalseValue() == FalseSI->getTrueValue()) {
+      Value *Xor = Builder.CreateXor(TrueSI->getCondition(), CondVal, "xor");
+      return SelectInst::Create(Xor, TrueSI->getFalseValue(),
+                                TrueSI->getTrueValue());
+    }
+  }
+
   // select(C, Z, binop(select(C, X, Y), W)) -> select(C, Z, binop(Y, W))
   BinaryOperator *FalseBO;
   if (match(FalseVal, m_OneUse(m_BinOp(FalseBO))) && !FalseBO->isIntDivRem()) {
@@ -4081,3 +4143,4 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {

   return nullptr;
 }
